import { cn } from "@/lib/utils";
import {
  Card,
  CardContent,
} from "@/components/ui/card";
import { Shield } from "lucide-react";

export function FeatureCard({ className, ...props }: React.ComponentPropsWithoutRef<"div">) {
    return(
        <Card
            className={cn(
                "bg-white shadow-lg rounded-lg hover:shadow-xl transition-shadow duration-300",
                className
            )}
            {...props}>
            <CardContent className="p-5 text-left">
              <div className="mb-3">
                <Shield className="w-5 h-5 text-gray-700" strokeWidth={2} />
              </div>
              <h4 className="text-base font-bold mb-2 text-gray-900">
                Secure Storage
              </h4>
              <p className="text-gray-600 text-sm leading-relaxed">
                Safe and reliable units for your personal or business
              </p>
            </CardContent>
        </Card>
    );
}